import { hasInjectionContext, inject } from "vue";
import {
  useHead as headCore,
  useHeadSafe as headSafe,
  headSymbol,
  useSeoMeta as seoMeta,
  useServerHead as serverHead,
  useServerHeadSafe as serverHeadSafe,
  useServerSeoMeta as serverSeoMeta
} from "@unhead/vue";
import { tryUseNuxtApp } from "#app/nuxt";
export function injectHead(nuxtApp) {
  const nuxt = nuxtApp || tryUseNuxtApp();
  return nuxt?.ssrContext?.head || nuxt?.runWithContext(() => {
    if (hasInjectionContext()) {
      return inject(headSymbol);
    }
  });
}
export function useHead(input, options = {}) {
  const head = injectHead(options.nuxt);
  if (head) {
    return headCore(input, { head, ...options });
  }
}
export function useHeadSafe(input, options = {}) {
  const head = injectHead(options.nuxt);
  if (head) {
    return headSafe(input, { head, ...options });
  }
}
export function useSeoMeta(input, options = {}) {
  const head = injectHead(options.nuxt);
  if (head) {
    return seoMeta(input, { head, ...options });
  }
}
export function useServerHead(input, options = {}) {
  const head = injectHead(options.nuxt);
  if (head) {
    return serverHead(input, { head, ...options });
  }
}
export function useServerHeadSafe(input, options = {}) {
  const head = injectHead(options.nuxt);
  if (head) {
    return serverHeadSafe(input, { head, ...options });
  }
}
export function useServerSeoMeta(input, options = {}) {
  const head = injectHead(options.nuxt);
  if (head) {
    return serverSeoMeta(input, { head, ...options });
  }
}
import type { PublicBlockNode, PublicSchemaTree } from '~/types/public'

type SchemaInput = PublicSchemaTree | PublicBlockNode[] | null | undefined

function isBlockNode(value: unknown): value is PublicBlockNode {
  return Boolean(value) && typeof value === 'object'
}

function extractNodeChildren(value: unknown): PublicBlockNode[] {
  return Array.isArray(value) ? value.filter(isBlockNode) : []
}

function getPropsRecord(value: unknown): Record<string, unknown> | null {
  if (!value || typeof value !== 'object' || Array.isArray(value)) {
    return null
  }

  const props = (value as Record<string, unknown>).props
  return props && typeof props === 'object' && !Array.isArray(props)
    ? props as Record<string, unknown>
    : null
}

export function normalizeSchemaNodes(schema?: SchemaInput): PublicBlockNode[] {
  if (!schema) {
    return []
  }

  if (Array.isArray(schema)) {
    return extractNodeChildren(schema)
  }

  if (Array.isArray(schema.elements)) {
    return extractNodeChildren(schema.elements)
  }

  if (Array.isArray(schema.children)) {
    return extractNodeChildren(schema.children)
  }

  const props = getPropsRecord(schema)

  if (Array.isArray(props?.elements)) {
    return extractNodeChildren(props.elements)
  }

  if (Array.isArray(props?.children)) {
    return extractNodeChildren(props.children)
  }

  if (Array.isArray(props?.content)) {
    return extractNodeChildren(props.content)
  }

  return []
}

export function getNodeChildren(node?: PublicBlockNode | null): PublicBlockNode[] {
  if (!node) {
    return []
  }

  if (Array.isArray(node.children)) {
    return node.children.filter(isBlockNode)
  }

  if (Array.isArray(node.elements)) {
    return extractNodeChildren(node.elements)
  }

  if (Array.isArray(node.content)) {
    return extractNodeChildren(node.content)
  }

  const props = getPropsRecord(node)

  if (Array.isArray(props?.children)) {
    return extractNodeChildren(props.children)
  }

  if (Array.isArray(props?.elements)) {
    return extractNodeChildren(props.elements)
  }

  if (Array.isArray(props?.content)) {
    return extractNodeChildren(props.content)
  }

  return []
}

export function getNodeKey(node: PublicBlockNode, index: number): string {
  const key = node.id ?? node._key ?? node.type ?? 'block'
  return `${String(key)}:${index}`
}

export function normalizeBlockType(type?: string | null): string {
  return (type || '')
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '')
}
<script setup lang="ts">
import { defineAsyncComponent } from 'vue'
import type { PublicBlockNode } from '~/types/public'
import { getNodeChildren, getNodeKey, normalizeBlockType } from '~/lib/schema'

defineOptions({ name: 'ElementRenderer' })

const props = defineProps<{ node: PublicBlockNode }>()
const isDev = import.meta.dev

const registry: Record<string, any> = {
  header: defineAsyncComponent(() => import('~/components/blocks/ContainerBlock.vue')),
  body: defineAsyncComponent(() => import('~/components/blocks/ContainerBlock.vue')),
  footer: defineAsyncComponent(() => import('~/components/blocks/ContainerBlock.vue')),
  container: defineAsyncComponent(() => import('~/components/blocks/ContainerBlock.vue')),
  '2col': defineAsyncComponent(() => import('~/components/blocks/ContainerBlock.vue')),
  '3col': defineAsyncComponent(() => import('~/components/blocks/ContainerBlock.vue')),
  text: defineAsyncComponent(() => import('~/components/blocks/TextBlock.vue')),
  section: defineAsyncComponent(() => import('~/components/blocks/SectionBlock.vue')),
  image: defineAsyncComponent(() => import('~/components/blocks/ImageBlock.vue')),
  link: defineAsyncComponent(() => import('~/components/blocks/LinkBlock.vue')),
  menu: defineAsyncComponent(() => import('~/components/blocks/MenuBlock.vue')),
  hero: defineAsyncComponent(() => import('~/components/blocks/HeroBlock.vue')),
  contactform: defineAsyncComponent(() => import('~/components/blocks/ContactFormBlock.vue'))
}

const component = computed(() => registry[normalizeBlockType(props.node?.type)])
const fallbackChildren = computed(() => getNodeChildren(props.node))
const shouldRenderFallback = computed(() => import.meta.dev || fallbackChildren.value.length > 0)
</script>

<template>
  <component v-if="component" :is="component" :node="node" />
  <div v-else-if="shouldRenderFallback" class="wt-unknown-block" data-unsupported-block="true">
    <p v-if="isDev" class="wt-unknown-label">
      Unsupported content block
    </p>
    <ElementRenderer
      v-for="(child, index) in fallbackChildren"
      :key="getNodeKey(child, index)"
      :node="child"
    />
  </div>
</template>

<style scoped>
.wt-unknown-block {
  display: contents;
}

.wt-unknown-label {
  margin: 0;
  color: var(--wt-color-muted);
  font-size: 0.875rem;
}
</style>
<script setup lang="ts">
import type { PublicBlockNode, PublicSchemaTree } from '~/types/public'
import ElementRenderer from '~/components/renderer/ElementRenderer.vue'
import { getNodeKey, normalizeSchemaNodes } from '~/lib/schema'

const props = withDefaults(defineProps<{
  schema?: PublicSchemaTree | PublicBlockNode[] | null
  scope?: string
  as?: string
}>(), {
  as: 'div'
})

const nodes = computed(() => normalizeSchemaNodes(props.schema))
</script>

<template>
  <component :is="as" v-if="nodes.length" class="wt-schema-renderer" :data-scope="scope">
    <ElementRenderer
      v-for="(node, index) in nodes"
      :key="getNodeKey(node, index)"
      :node="node"
    />
  </component>
</template>
import type { InjectionKey } from 'vue'
import type { PublicBlockNode, PublicMenu, PublicMenuItem, PublicSchemaTree } from '~/types/public'

export type RuntimeMenuItem = PublicMenuItem
export type RuntimeMenuDefinition = PublicMenu

export const runtimeMenusKey: InjectionKey<ComputedRef<RuntimeMenuDefinition[]>> = Symbol('runtime-menus')
export const runtimeHeaderSchemaKey: InjectionKey<ComputedRef<PublicSchemaTree | PublicBlockNode[] | null | undefined>> = Symbol('runtime-header-schema')
export const runtimeHeaderOverlayKey: InjectionKey<ComputedRef<boolean>> = Symbol('runtime-header-overlay')

type LooseRecord = Record<string, unknown>

type RuntimeStyleValue = string | number
type RuntimeStyleMap = Record<string, RuntimeStyleValue>

function asRecord(value: unknown): LooseRecord | null {
  return value && typeof value === 'object' && !Array.isArray(value) ? value as LooseRecord : null
}

function isRuntimeStyleValue(value: unknown): value is RuntimeStyleValue {
  return typeof value === 'string' || typeof value === 'number'
}

export function getNodeContent(node: PublicBlockNode | Record<string, unknown> | null | undefined): unknown {
  const record = asRecord(node)

  if (record?.content !== undefined) {
    return record.content
  }

  return getNodePropsRecord(node)?.content
}

export function getNodeContentRecord(node: PublicBlockNode | Record<string, unknown> | null | undefined): LooseRecord | null {
  return asRecord(getNodeContent(node))
}

export function getNodePropsRecord(node: PublicBlockNode | Record<string, unknown> | null | undefined): LooseRecord | null {
  return asRecord(asRecord(node)?.props)
}

export function getNodeStyles(node: PublicBlockNode | Record<string, unknown> | null | undefined): RuntimeStyleMap {
  const record = asRecord(node)
  const styles = asRecord(record?.styles ?? getNodePropsRecord(node)?.styles)

  if (!styles) {
    return {}
  }

  return Object.fromEntries(
    Object.entries(styles).filter(([, value]) => isRuntimeStyleValue(value))
  )
}

export function getNodeClasses(node: PublicBlockNode | Record<string, unknown> | null | undefined): string {
  const record = asRecord(node)
  const value = record?.classes ?? getNodePropsRecord(node)?.classes
  return typeof value === 'string' ? value.trim() : ''
}

export function getNodeField(node: PublicBlockNode | Record<string, unknown> | null | undefined, key: string): unknown {
  const record = asRecord(node)

  if (record && record[key] !== undefined) {
    return record[key]
  }

  const props = getNodePropsRecord(node)
  if (props && props[key] !== undefined) {
    return props[key]
  }

  const content = getNodeContentRecord(node)
  return content ? content[key] : undefined
}

export function getStringField(node: PublicBlockNode | Record<string, unknown> | null | undefined, ...keys: string[]): string | null {
  for (const key of keys) {
    const value = getNodeField(node, key)
    if (typeof value === 'string' && value.trim()) {
      return value
    }
  }

  return null
}

export function getBooleanField(node: PublicBlockNode | Record<string, unknown> | null | undefined, ...keys: string[]): boolean {
  for (const key of keys) {
    const value = getNodeField(node, key)
    if (typeof value === 'boolean') {
      return value
    }
  }

  return false
}

export function getArrayField<T = unknown>(node: PublicBlockNode | Record<string, unknown> | null | undefined, ...keys: string[]): T[] {
  for (const key of keys) {
    const value = getNodeField(node, key)
    if (Array.isArray(value)) {
      return value as T[]
    }
  }

  return []
}
import { getNodeContentRecord, getNodeStyles, getStringField } from '~/lib/blockRuntime'
import { getNodeChildren, normalizeBlockType, normalizeSchemaNodes } from '~/lib/schema'
import type { PublicBlockNode, PublicSchemaTree } from '~/types/public'

type DeviceType = 'Mobile' | 'Tablet'
type RuntimeStyleValue = string | number
type RuntimeStyleMap = Record<string, RuntimeStyleValue>
type LooseRecord = Record<string, unknown>
type ResponsiveNodeContext = {
  scope?: 'header' | 'body' | 'footer'
  parentType?: string
  siblingTypes?: string[]
}

const MOBILE_BREAKPOINT_MAX = 767.98
const TABLET_BREAKPOINT_MIN = 768
const TABLET_BREAKPOINT_MAX = 1023.98
const DEVICE_CANVAS_WIDTH: Record<DeviceType, number> = {
  Mobile: 375,
  Tablet: 768,
}

const ROOT_TYPES = new Set(['body', 'header', 'footer', '__body', '__header', '__footer'])
const GENERATED_SECTION_SHELL_NAMES = new Set([
  'Hero - Modern Split',
  'About - Story Split',
  'Features - Card Grid',
  'Services - Offer Grid',
  'Testimonials - Quote Grid',
  'CTA - Banner',
  'FAQ - Stacked',
  'Contact - Split Form',
])
const GENERATED_GRID_NAMES = new Set([
  'Hero Columns',
  'About Columns',
  'Feature Grid',
  'Services Grid',
  'Testimonial Grid',
  'Contact Columns',
])
const GENERATED_CARD_MIN_HEIGHTS: Record<string, string> = {
  'Feature Card': '240px',
  'Service Card': '256px',
  'Testimonial Card': '248px',
}
const UNITLESS_PROPERTIES = new Set([
  'animationIterationCount',
  'aspectRatio',
  'flex',
  'flexGrow',
  'flexShrink',
  'fontWeight',
  'lineClamp',
  'lineHeight',
  'opacity',
  'order',
  'orphans',
  'widows',
  'zIndex',
  'zoom',
])

function asRecord(value: unknown): LooseRecord | null {
  return value && typeof value === 'object' && !Array.isArray(value)
    ? (value as LooseRecord)
    : null
}

function isRuntimeStyleValue(value: unknown): value is RuntimeStyleValue {
  return typeof value === 'string' || typeof value === 'number'
}

function getResponsiveSource(node: PublicBlockNode | Record<string, unknown> | null | undefined): LooseRecord | null {
  const record = asRecord(node)
  const props = asRecord(record?.props)
  return asRecord(record?.responsiveStyles ?? props?.responsiveStyles)
}

function getDeviceOverrideRecord(
  node: PublicBlockNode | Record<string, unknown> | null | undefined,
  device: DeviceType
): LooseRecord | null {
  const source = getResponsiveSource(node)
  return asRecord(device === 'Mobile' ? source?.mobile : source?.tablet)
}

function getDeviceOverrides(
  node: PublicBlockNode | Record<string, unknown> | null | undefined,
  device: DeviceType
): RuntimeStyleMap {
  const source = getDeviceOverrideRecord(node, device)

  if (!source) {
    return {}
  }

  return Object.fromEntries(
    Object.entries(source).filter(([, value]) => isRuntimeStyleValue(value))
  )
}

function parsePixelValue(value: unknown): number | null {
  if (typeof value === 'number' && Number.isFinite(value)) {
    return value
  }

  if (typeof value !== 'string' || !value.includes('px')) {
    return null
  }

  const parsed = Number.parseFloat(value)
  return Number.isFinite(parsed) ? parsed : null
}

function hasOwnDefinedValue(record: LooseRecord | null, property: string): boolean {
  return Boolean(record && record[property] !== undefined)
}

function getNodeType(node: PublicBlockNode | Record<string, unknown> | null | undefined): string {
  return normalizeBlockType(getStringField(node, 'type'))
}

function getNodeName(node: PublicBlockNode | Record<string, unknown> | null | undefined): string {
  return getStringField(node, 'name') || ''
}

function getGeneratedLayoutStyleOverrides(
  node: PublicBlockNode | Record<string, unknown> | null | undefined,
  device: 'Desktop' | DeviceType
): RuntimeStyleMap {
  const nodeName = getNodeName(node)

  if (device === 'Mobile') {
    return {}
  }

  if (GENERATED_SECTION_SHELL_NAMES.has(nodeName)) {
    return device === 'Desktop'
      ? {
          gap: '72px',
        }
      : {
          gap: '28px',
        }
  }

  if (nodeName === 'Section Intro') {
    return device === 'Desktop'
      ? { gap: '24px' }
      : { gap: '10px' }
  }

  if (GENERATED_GRID_NAMES.has(nodeName)) {
    return device === 'Desktop'
      ? { gap: '48px' }
      : { gap: '24px' }
  }

  if (nodeName === 'About Highlights') {
    return device === 'Desktop'
      ? { gap: '28px' }
      : { gap: '20px' }
  }

  if (nodeName === 'FAQ Stack') {
    return device === 'Desktop'
      ? { gap: '20px' }
      : { gap: '16px' }
  }

  if (nodeName === 'About Highlight') {
    return device === 'Desktop'
      ? {
          minHeight: '220px',
        }
      : {
          minHeight: '180px',
        }
  }

  const generatedCardMinHeight = GENERATED_CARD_MIN_HEIGHTS[nodeName]
  if (generatedCardMinHeight) {
    return device === 'Desktop'
      ? {
          minHeight: generatedCardMinHeight,
        }
      : {
          minHeight:
            nodeName === 'Feature Card'
              ? '200px'
              : nodeName === 'Service Card'
                ? '216px'
                : '208px',
        }
  }

  return {}
}

function getNodeVariant(node: PublicBlockNode | Record<string, unknown> | null | undefined): string {
  return (getStringField(node, 'variant') || '').trim().toLowerCase()
}

function getNodeSlot(node: PublicBlockNode | Record<string, unknown> | null | undefined): string {
  return (getStringField(node, 'slot') || '').trim().toLowerCase()
}

function getNodeIdValue(node: PublicBlockNode | Record<string, unknown> | null | undefined): string | null {
  const record = asRecord(node)
  const rawId = record?.id ?? record?._key

  if (typeof rawId === 'string' && rawId.trim()) {
    return rawId.trim()
  }

  if (typeof rawId === 'number' && Number.isFinite(rawId)) {
    return String(rawId)
  }

  return null
}

function toCssPropertyName(property: string): string {
  if (property.startsWith('--')) {
    return property
  }

  return property.replace(/[A-Z]/g, (match) => `-${match.toLowerCase()}`)
}

function toCssPropertyValue(property: string, value: RuntimeStyleValue): string {
  if (typeof value === 'number') {
    return UNITLESS_PROPERTIES.has(property) ? String(value) : `${value}px`
  }

  return value.replace(/[\r\n]+/g, ' ').trim()
}

function escapeAttributeValue(value: string): string {
  return value.replace(/\\/g, '\\\\').replace(/"/g, '\\"')
}

function buildCssRule(nodeId: string, styles: RuntimeStyleMap): string | null {
  const declarations = Object.entries(styles)
    .filter(([, value]) => isRuntimeStyleValue(value))
    .map(([property, value]) => {
      const cssValue = toCssPropertyValue(property, value)
      return cssValue
        ? `${toCssPropertyName(property)}: ${cssValue} !important;`
        : ''
    })
    .filter(Boolean)
    .join(' ')

  if (!declarations) {
    return null
  }

  return `[data-wt-node-id="${escapeAttributeValue(nodeId)}"] { ${declarations} }`
}

function shallowEqualStyles(a: RuntimeStyleMap, b: RuntimeStyleMap): boolean {
  const aKeys = Object.keys(a)
  const bKeys = Object.keys(b)

  if (aKeys.length !== bKeys.length) {
    return false
  }

  return aKeys.every((key) => a[key] === b[key])
}

export function getNodeDomId(node: PublicBlockNode | Record<string, unknown> | null | undefined): string | null {
  return getNodeIdValue(node)
}

export function getResponsiveNodeStyles(
  node: PublicBlockNode | Record<string, unknown> | null | undefined,
  device: DeviceType,
  canvasWidth = DEVICE_CANVAS_WIDTH[device],
  context: ResponsiveNodeContext = {}
): RuntimeStyleMap {
  const baseStyles = { ...getNodeStyles(node) }
  const colorMode = (getStringField(node, 'colorMode') || '').trim().toLowerCase()
  if (getNodeType(node) === 'menu' && colorMode === 'auto') {
    delete baseStyles.color
  }
  let mergedStyles: RuntimeStyleMap = {
    ...baseStyles,
    ...getDeviceOverrides(node, device),
  }

  const deviceOverrideRecord = getDeviceOverrideRecord(node, device)
  const hasDeviceOverride = (property: string) =>
    hasOwnDefinedValue(deviceOverrideRecord, property)

  const width = mergedStyles.width
  const originalWidth = width
  const widthPx = parsePixelValue(width)
  const leftPx = parsePixelValue(mergedStyles.left)
  const marginLeftPx = parsePixelValue(mergedStyles.marginLeft)
  const type = getNodeType(node)
  const isRootSection = ROOT_TYPES.has(type)
  const hasFixedPixelWidth = widthPx !== null
  const isImageElement = type === 'image'
  const isBrandLogoElement = isImageElement && /brand/i.test(getNodeName(node))
  const parentType = normalizeBlockType(context.parentType || '')
  const isHeaderImage = isImageElement && parentType === 'header'
  const siblingTypes = context.siblingTypes || []
  const scope = context.scope
  const variant = getNodeVariant(node)
  const slot = getNodeSlot(node)
  const isHeaderRoot = type === 'header'
  const isFooterRoot = type === 'footer'
  const isHeaderMenu =
    type === 'menu' &&
    (
      parentType === 'header' ||
      variant.includes('header') ||
      slot === 'primary' ||
      slot === 'utility'
    )
  const isFooterMenu =
    type === 'menu' &&
    (
      parentType === 'footer' ||
      variant.includes('footer') ||
      slot === 'legal' ||
      slot === 'footer' ||
      slot === 'social'
    )
  const isHeaderLink = type === 'link' && parentType === 'header'
  const hasMenuSibling = siblingTypes.includes('menu')
  const hasImageSibling = siblingTypes.includes('image')
  const imageContent = getNodeContentRecord(node)
  const hasImageSource =
    isImageElement &&
    typeof imageContent?.src === 'string' &&
    imageContent.src.trim().length > 0

  if (isImageElement && !isBrandLogoElement && !isHeaderImage && !hasDeviceOverride('width')) {
    mergedStyles.width = '100%'
    if (!hasDeviceOverride('maxWidth')) mergedStyles.maxWidth = '100%'
    if (!hasDeviceOverride('left')) mergedStyles.left = '0'
    if (!hasDeviceOverride('marginLeft')) mergedStyles.marginLeft = '0'
    if (!hasDeviceOverride('right')) mergedStyles.right = 'auto'
  }

  if (hasImageSource && !isBrandLogoElement && !isHeaderImage && !hasDeviceOverride('height')) {
    mergedStyles.height = 'auto'
    if (!hasDeviceOverride('minHeight')) mergedStyles.minHeight = '0px'
  }

  if (hasFixedPixelWidth && !isRootSection && !isBrandLogoElement && !isHeaderImage) {
    mergedStyles.width = '100%'
    mergedStyles.maxWidth = '100%'
    mergedStyles.left = '0'
    mergedStyles.marginLeft = '0'
    mergedStyles.right = 'auto'
  }

  if (typeof width === 'string' && width.includes('px')) {
    const widthValue = Number.parseInt(width, 10)

    if (
      Number.isFinite(widthValue) &&
      widthValue > canvasWidth &&
      hasFixedPixelWidth &&
      isRootSection
    ) {
      mergedStyles.width = '100%'
      mergedStyles.maxWidth = width

      if (
        mergedStyles.position === 'absolute' ||
        mergedStyles.position === 'relative'
      ) {
        mergedStyles.left = '0'
        mergedStyles.marginLeft = '0'
        mergedStyles.right = 'auto'
      }
    }
  }

  const couldOverflowFromOffsets =
    hasFixedPixelWidth &&
    isRootSection &&
    (
      (leftPx !== null && leftPx + widthPx > canvasWidth) ||
      (marginLeftPx !== null && marginLeftPx + widthPx > canvasWidth)
    )

  if (couldOverflowFromOffsets) {
    mergedStyles.width = '100%'

    if (typeof originalWidth === 'string' && originalWidth.includes('px')) {
      mergedStyles.maxWidth = originalWidth
    }

    mergedStyles.left = '0'
    mergedStyles.marginLeft = '0'
    mergedStyles.right = 'auto'
  }

  if (
    mergedStyles.position === 'absolute' ||
    mergedStyles.position === 'relative'
  ) {
    const positionedLeft = parsePixelValue(mergedStyles.left)

    if (positionedLeft !== null && positionedLeft >= canvasWidth - 20) {
      mergedStyles.left = '0'
      mergedStyles.marginLeft = '0'
      mergedStyles.right = 'auto'
    }
  }

  if (
    device === 'Mobile' &&
    typeof mergedStyles.fontSize === 'string'
  ) {
    const fontSize = Number.parseInt(mergedStyles.fontSize, 10)
    if (Number.isFinite(fontSize) && fontSize > 16) {
      mergedStyles.fontSize = `${Math.max(14, fontSize * 0.875)}px`
    }
  }

  if (
    device === 'Mobile' &&
    typeof mergedStyles.padding === 'string'
  ) {
    const padding = Number.parseInt(mergedStyles.padding, 10)
    if (Number.isFinite(padding) && padding > 20) {
      mergedStyles.padding = `${Math.max(10, padding * 0.75)}px`
    }
  }

  if (
    device === 'Tablet' &&
    typeof mergedStyles.fontSize === 'string'
  ) {
    const fontSize = Number.parseInt(mergedStyles.fontSize, 10)
    if (Number.isFinite(fontSize) && fontSize > 20) {
      mergedStyles.fontSize = `${Math.max(16, fontSize * 0.9)}px`
    }
  }

  mergedStyles = {
    ...mergedStyles,
    ...getGeneratedLayoutStyleOverrides(node, device),
  }

  // Published payloads may only contain base styles with no responsive overrides.
  // These layout heuristics keep common header/footer compositions usable at real narrow widths.
  if (
    (device === 'Mobile' || device === 'Tablet') &&
    mergedStyles.display === 'flex' &&
    (scope === 'header' || scope === 'footer') &&
    !hasDeviceOverride('flexWrap')
  ) {
    mergedStyles.flexWrap = 'wrap'
  }

  if (
    scope === 'footer' &&
    device === 'Mobile' &&
    mergedStyles.justifyContent === 'space-between' &&
    !hasDeviceOverride('justifyContent')
  ) {
    mergedStyles.justifyContent = 'flex-start'
  }

  if (
    device === 'Tablet' &&
    isHeaderRoot &&
    (
      mergedStyles.display === 'flex' ||
      (hasImageSibling && hasMenuSibling)
    )
  ) {
    if (!hasDeviceOverride('display')) mergedStyles.display = 'flex'
    if (!hasDeviceOverride('flexWrap')) mergedStyles.flexWrap = 'wrap'
  }

