  const explicitHomepage = routes.find((route) => route.isHomepage || normalizePublicPath(route.path) === '/')
  if (explicitHomepage) {
    return normalizePublicPath(explicitHomepage.path)
  }

  const fallbackSegments = [data?.siteKey, data?.publicIdentifier].filter(
    (value): value is string => typeof value === 'string' && value.trim().length > 0
  )

  if (!fallbackSegments.length) {
    return null
  }

  const fallbackPaths = new Set(fallbackSegments.map((segment) => `/${segment.trim()}`))

  for (const route of routes) {
    const routePath = normalizePublicPath(route.path)
    if (routePath && fallbackPaths.has(routePath)) {
      return routePath
    }

    const slug = typeof route.slug === 'string' ? route.slug.trim() : ''
    if (slug && fallbackSegments.includes(slug)) {
      return routePath
    }
  }

  return null
}

function getNestedNodeCount(node: unknown): number {
  if (!node || typeof node !== 'object') {
    return 0
  }

  const candidate = node as { content?: unknown[]; children?: unknown[]; elements?: unknown[] }
  return candidate.content?.length || candidate.children?.length || candidate.elements?.length || 0
}

function getSchemaChildCount(schema?: PublicSchemaTree | unknown[] | null): number {
  if (!schema) {
    return 0
  }

  if (Array.isArray(schema)) {
    return schema.reduce((count, node) => count + getNestedNodeCount(node), 0)
  }

  if (Array.isArray(schema.elements)) {
    return schema.elements.reduce((count, node) => count + getNestedNodeCount(node), 0)
  }

  if (Array.isArray(schema.children)) {
    return schema.children.reduce((count, node) => count + getNestedNodeCount(node), 0)
  }

  return getNestedNodeCount(schema)
}

function siteShellLooksEmpty(site?: SitePayload | null): boolean {
  const headerCount = getSchemaChildCount(site?.headerSchema)
  const footerCount = getSchemaChildCount(site?.footerSchema)
  return headerCount === 0 || footerCount === 0
}

async function withFreshSiteShell(payload: PublicPageResponse, host: string): Promise<PublicPageResponse> {
  if (!siteShellLooksEmpty(payload.site)) {
    return payload
  }

  try {
    const siteResponse = await fetchPublicSite(host)

    if (!siteShellLooksEmpty(siteResponse.site)) {
      return {
        ...payload,
        site: siteResponse.site
      }
    }
  } catch {
    return payload
  }

  return payload
}

async function fetchResolvedPublicPage(host: string, path: string): Promise<PublicPageResponse> {
  try {
    const payload = await fetchPublicPage(host, path)
    return await withFreshSiteShell(payload, host)
  } catch (error) {
    if (path !== '/' || getStatusCode(error) !== 404) {
      throw error
    }

    let fallbackPath: string | null = null

    try {
      const routes = await fetchPublicRoutes(host)
      fallbackPath = resolveHomepageFallbackPath(routes)
    } catch {
      fallbackPath = null
    }

    if (!fallbackPath || fallbackPath === path) {
      throw error
    }

    try {
      const payload = await fetchPublicPage(host, fallbackPath)
      return await withFreshSiteShell(payload, host)
    } catch (fallbackError) {
      if (getStatusCode(fallbackError) === 404) {
        throw error
      }

      throw fallbackError
    }
  }
}

export async function usePublicPage() {
  const route = useRoute()
  const config = useRuntimeConfig()
  const host = getRequestHost()
  const path = computed(() => normalizePublicPath(route.path) || '/')

  const { data, error } = await useAsyncData<PublicPageResponse | null>(
    `public-page:${host}`,
    () => fetchResolvedPublicPage(host, path.value),
    {
      watch: [path],
      default: () => null,
    }
  )

  if (error.value) {
    throw resolvePageError(error.value, host, config.public.apiBase)
  }

  if (!data.value?.entity || !data.value?.site || !data.value?.page) {
    if (import.meta.dev) {
      throw createError({
        statusCode: 404,
        statusMessage: `Page payload missing for host "${host}" and path "${path.value}". API base: ${config.public.apiBase}.`
      })
    }

    throw createError({ statusCode: 404, statusMessage: 'Page not found' })
  }

  return data
}
import type { PublicEntityPayload, PublicRoutesResponse, PublicSiteResponse } from '~/types/public'
import { isLocalPlatformRequestHost, normalizeHost, preferRequestHost } from '~/lib/host'

const DEFAULT_ROBOTS_TXT = 'User-agent: *\nAllow: /\n'
const VALID_CHANGE_FREQUENCIES = new Set([
  'always',
  'hourly',
  'daily',
  'weekly',
  'monthly',
  'yearly',
  'never'
])

type PublicHostSource = Pick<PublicEntityPayload, 'canonicalHost' | 'resolvedHost'> | Pick<PublicRoutesResponse, 'canonicalHost' | 'resolvedHost'>

function hasText(value: unknown): value is string {
  return typeof value === 'string' && value.trim().length > 0
}

function escapeXml(value: string): string {
  return value
    .replaceAll('&', '&amp;')
    .replaceAll('<', '&lt;')
    .replaceAll('>', '&gt;')
    .replaceAll('"', '&quot;')
    .replaceAll("'", '&apos;')
}

function normalizeMultilineText(value: string): string {
  return value.replace(/\r\n?/g, '\n').trim()
}

function normalizePublicPath(path?: string | null): string | null {
  if (typeof path !== 'string') {
    return null
  }

  if (!path.trim()) {
    return '/'
  }

  try {
    const normalized = new URL(path, 'https://webtree.invalid')
    if (!['http:', 'https:'].includes(normalized.protocol)) {
      return null
    }

    return normalized.pathname || '/'
  } catch {
    const trimmed = path.trim().split(/[?#]/)[0] || '/'
    return trimmed.startsWith('/') ? trimmed : `/${trimmed}`
  }
}

function normalizeLastModified(value?: string): string | null {
  if (!hasText(value)) {
    return null
  }

  const date = new Date(value)
  return Number.isNaN(date.valueOf()) ? null : date.toISOString()
}

function normalizeChangeFrequency(value?: string): string | null {
  if (!hasText(value)) {
    return null
  }

  const normalized = value.trim().toLowerCase()
  return VALID_CHANGE_FREQUENCIES.has(normalized) ? normalized : null
}

function normalizePriority(value?: number): string | null {
  if (typeof value !== 'number' || Number.isNaN(value)) {
    return null
  }

  const clamped = Math.max(0, Math.min(1, value))
  return String(clamped)
}

export function normalizeSiteProtocol(value?: string | null): 'http' | 'https' {
  return value === 'http' ? 'http' : 'https'
}

export function resolvePublicHost(source: PublicHostSource | null | undefined, requestHost: string, platformBaseDomain?: string | null): string {
  const normalizedRequestHost = normalizeHost(requestHost)

  if (isLocalPlatformRequestHost(normalizedRequestHost, platformBaseDomain)) {
    return normalizedRequestHost
  }

  const preferredHost = normalizeHost(source?.canonicalHost || source?.resolvedHost || normalizedRequestHost) || normalizedRequestHost
  return preferRequestHost(preferredHost, normalizedRequestHost)
}

export function buildAbsolutePublicUrl(
  source: PublicHostSource | null | undefined,
  requestHost: string,
  path: string,
  siteProtocol = 'https',
  platformBaseDomain?: string | null
): string {
  const host = resolvePublicHost(source, requestHost, platformBaseDomain) || 'localhost'
  const pathname = normalizePublicPath(path) || '/'
  const protocol = normalizeSiteProtocol(siteProtocol)
  return new URL(pathname, `${protocol}://${host}`).toString()
}

export function buildRobotsTxt(
  data: PublicSiteResponse,
  requestHost: string,
  siteProtocol = 'https',
  platformBaseDomain?: string | null
): string {
  const explicitPolicy = hasText(data.site.defaults?.robotsTxt) ? data.site.defaults.robotsTxt : ''

  const normalizedBasePolicy = explicitPolicy
    ? normalizeMultilineText(explicitPolicy)
        .split('\n')
        .filter((line) => !/^sitemap:/i.test(line.trim()))
        .join('\n')
    : DEFAULT_ROBOTS_TXT.trim()

  const basePolicy = normalizedBasePolicy || DEFAULT_ROBOTS_TXT.trim()

  const sitemapUrl = buildAbsolutePublicUrl(data.entity, requestHost, '/sitemap.xml', siteProtocol, platformBaseDomain)
  return `${basePolicy}\nSitemap: ${sitemapUrl}\n`
}

export function buildSitemapXml(
  data: PublicRoutesResponse,
  requestHost: string,
  siteProtocol = 'https',
  platformBaseDomain?: string | null
): string {
  const seen = new Set<string>()
  const items = (data.routes || [])
    .filter((route) => !route.noindex)
    .flatMap((route) => {
      const path = normalizePublicPath(route.path)
      if (!path) {
        return []
      }

      const location = buildAbsolutePublicUrl(data, requestHost, path, siteProtocol, platformBaseDomain)
      if (seen.has(location)) {
        return []
      }

      seen.add(location)

      const fragments = [`<loc>${escapeXml(location)}</loc>`]
      const lastModified = normalizeLastModified(route.updatedAt)
      const changeFrequency = normalizeChangeFrequency(route.changeFrequency)
      const priority = normalizePriority(route.priority)

      if (lastModified) {
        fragments.push(`<lastmod>${escapeXml(lastModified)}</lastmod>`)
      }

      if (changeFrequency) {
        fragments.push(`<changefreq>${escapeXml(changeFrequency)}</changefreq>`)
      }

      if (priority) {
        fragments.push(`<priority>${escapeXml(priority)}</priority>`)
      }

      return [`  <url>${fragments.join('')}</url>`]
    })

  return [
    '<?xml version="1.0" encoding="UTF-8"?>',
    '<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">',
    ...items,
    '</urlset>'
  ].join('\n')
}

export function getPublicFeedStatusCode(error: unknown): number {
  if (!error || typeof error !== 'object') {
    return 500
  }

  if ('statusCode' in error && typeof error.statusCode === 'number') {
    return error.statusCode
  }

  if ('status' in error && typeof error.status === 'number') {
    return error.status
  }

  if ('response' in error && error.response && typeof error.response === 'object' && 'status' in error.response && typeof error.response.status === 'number') {
    return error.response.status
  }

  if ('data' in error && error.data && typeof error.data === 'object' && 'statusCode' in error.data && typeof error.data.statusCode === 'number') {
    return error.data.statusCode
  }

  return 500
}
import type { Ref } from 'vue'
import type { JsonValue, PublicPageResponse, SeoPayload } from '~/types/public'
import { getRequestHost } from '~/lib/host'
import { normalizeSiteProtocol, resolvePublicHost } from '~/lib/publicFeed'

function isJsonObject(value: unknown): value is Record<string, JsonValue> {
  return Boolean(value) && typeof value === 'object' && !Array.isArray(value)
}

function buildTitle(title: string, suffix?: string | null): string {
  if (!suffix || !title) {
    return title
  }

  if (title.endsWith(suffix)) {
    return title
  }

  const separator = /^\s|^[|:-]/.test(suffix) ? '' : ' '
  return `${title}${separator}${suffix}`
}

function normalizePath(path?: string | null): string {
  if (!path) {
    return '/'
  }

  return path.startsWith('/') ? path : `/${path}`
}

function toAbsoluteUrl(value: string | null | undefined, baseUrl?: string | null): string | null {
  if (!value) {
    return null
  }

  try {
    return new URL(value, baseUrl || undefined).toString()
  } catch {
    return null
  }
}

function buildRobots(seo: SeoPayload | undefined, fallback: string): string {
  const directives = new Set(
    (seo?.robots || fallback)
      .split(',')
      .map((directive) => directive.trim())
      .filter(Boolean)
  )

  if (seo?.noindex) {
    directives.delete('index')
    directives.delete('follow')
    directives.add('noindex')
    directives.add('nofollow')
  }

  if (seo?.noarchive) {
    directives.add('noarchive')
  }

  return Array.from(directives).join(', ') || fallback
}

function normalizeStructuredData(value: SeoPayload['structuredData'] | string | undefined): string[] {
  if (!value) {
    return []
  }

  if (typeof value === 'string') {
    try {
      return normalizeStructuredData(JSON.parse(value) as SeoPayload['structuredData'])
    } catch {
      return []
    }
  }

  const items = Array.isArray(value) ? value : [value]

  return items.flatMap((item) => {
    if (!isJsonObject(item)) {
      return []
    }

    try {
      return [JSON.stringify(item)]
    } catch {
      return []
    }
  })
}

export function usePublicSeo(payload: Ref<PublicPageResponse | null | undefined>) {
  const config = useRuntimeConfig()
  const requestHost = getRequestHost()
  const siteProtocol = normalizeSiteProtocol(config.public.siteProtocol)

  useHead(() => {
    const entity = payload.value?.entity
    const site = payload.value?.site
    const page = payload.value?.page
    const seo = page?.seo
    const siteName = site?.defaults?.siteName || entity?.siteKey || 'Website'
    const publicHost = resolvePublicHost(entity, requestHost, config.public.platformBaseDomain)
    const baseUrl = publicHost ? toAbsoluteUrl(`${siteProtocol}://${publicHost}`) : null
    const fallbackTitle = page?.title || siteName
    const title = buildTitle(seo?.title || fallbackTitle, site?.defaults?.titleSuffix)
    const description = seo?.description || page?.description || site?.defaults?.defaultDescription || ''
    const canonical = toAbsoluteUrl(seo?.canonicalUrl || normalizePath(page?.path), baseUrl)
    const robots = buildRobots(seo, site?.defaults?.robotsDefault || 'index,follow')
    const ogImage = toAbsoluteUrl(seo?.ogImage || site?.defaults?.defaultOgImage, baseUrl)
    const twitterImage = toAbsoluteUrl(seo?.twitterImage || ogImage, baseUrl)
    const favicon = toAbsoluteUrl(entity?.favicon, baseUrl)
    const structuredData = normalizeStructuredData(seo?.structuredData || site?.defaults?.structuredDataJsonLd)
    const link: Array<{ rel: string; href: string }> = []
    const meta: Array<Record<string, string>> = []

    if (description) {
      meta.push({ name: 'description', content: description })
    }

    meta.push({ name: 'robots', content: robots })
    meta.push({ property: 'og:title', content: seo?.ogTitle || title })
    meta.push({ property: 'og:description', content: seo?.ogDescription || description })
    meta.push({ property: 'og:type', content: seo?.ogType || 'website' })

    if (siteName) {
      meta.push({ property: 'og:site_name', content: siteName })
    }

    if (canonical) {
      meta.push({ property: 'og:url', content: canonical })
    }

    meta.push({ name: 'twitter:card', content: seo?.twitterCard || site?.defaults?.defaultTwitterCard || 'summary_large_image' })
    meta.push({ name: 'twitter:title', content: seo?.twitterTitle || title })
    meta.push({ name: 'twitter:description', content: seo?.twitterDescription || description })

    if (ogImage) {
      meta.push({ property: 'og:image', content: ogImage })
    }

    if (twitterImage) {
      meta.push({ name: 'twitter:image', content: twitterImage })
    }

    if (seo?.articlePublishedTime) {
      meta.push({ property: 'article:published_time', content: seo.articlePublishedTime })
    }

    if (seo?.articleModifiedTime) {
      meta.push({ property: 'article:modified_time', content: seo.articleModifiedTime })
    }

    if (canonical) {
      link.push({ rel: 'canonical', href: canonical })
    }

    if (favicon) {
      link.push({ rel: 'icon', href: favicon })
    }

    return {
      title,
      htmlAttrs: {
        lang: entity?.defaultLocale || 'en'
      },
      link,
      meta,
      script: structuredData.map((item, index) => ({
        key: `json-ld:${index}`,
        type: 'application/ld+json',
        children: item
      }))
    }
  })
}
<script setup lang="ts">
import SchemaRenderer from '~/components/renderer/SchemaRenderer.vue'
import { runtimeHeaderOverlayKey, runtimeHeaderSchemaKey, runtimeMenusKey } from '~/lib/blockRuntime'
import { buildResponsiveStylesheet } from '~/lib/responsiveRuntime'
import { buildCssVars } from '~/lib/styles'
import { mergeVaryHeader } from '~/lib/host'

const payload = await usePublicPage()
usePublicSeo(payload)

const cssVars = computed(() => buildCssVars(payload.value?.site?.builderStyles))
const runtimeMenus = computed(() => payload.value?.site?.menus ?? [])
const pageWidthMode = computed(() => {
  const styles = payload.value?.site?.builderStyles
  const page = styles && typeof styles === 'object' && !Array.isArray(styles) ? styles.page : null

  if (!page || typeof page !== 'object' || Array.isArray(page)) {
    return 'contained'
  }

  return page.widthMode === 'full' ? 'full' : 'contained'
})
const runtimeHeaderSchema = computed(() => payload.value?.site?.headerSchema)
const runtimeHeaderOverlay = computed(() => {
  const headerSchema = payload.value?.site?.headerSchema

  if (!headerSchema || typeof headerSchema !== 'object' || Array.isArray(headerSchema)) {
    return false
  }

  const behavior = 'behavior' in headerSchema ? headerSchema.behavior : null
  return Boolean(
    behavior &&
    typeof behavior === 'object' &&
    !Array.isArray(behavior) &&
    'overlay' in behavior &&
    behavior.overlay === true
    )
})
const runtimeHeaderPosition = computed(() => {
  const headerSchema = payload.value?.site?.headerSchema

  if (!headerSchema || typeof headerSchema !== 'object' || Array.isArray(headerSchema)) {
    return 'static'
  }

  const behavior = 'behavior' in headerSchema ? headerSchema.behavior : null
  if (
    behavior &&
    typeof behavior === 'object' &&
    !Array.isArray(behavior) &&
    'position' in behavior &&
    behavior.position === 'sticky'
  ) {
    return 'sticky'
  }

  return 'static'
})
const responsiveCss = computed(() =>
  buildResponsiveStylesheet({
    headerSchema: payload.value?.site?.headerSchema,
    bodySchema: payload.value?.page?.bodySchema,
    footerSchema: payload.value?.site?.footerSchema,
  })
)

provide(runtimeMenusKey, runtimeMenus)
provide(runtimeHeaderSchemaKey, runtimeHeaderSchema)
provide(runtimeHeaderOverlayKey, runtimeHeaderOverlay)

useHead(() => ({
  style: responsiveCss.value
    ? [{
        key: 'wt-responsive-runtime',
        textContent: responsiveCss.value,
      }]
    : [],
}))

if (import.meta.server) {
  const vary = useResponseHeader('vary')
  vary.value = mergeVaryHeader(vary.value, ['Host', 'X-Forwarded-Host'])
}
</script>

